import java.io.*;

public class CommandInjectionSecure {
    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));

        System.out.print("Enter a command to execute: ");
        String command = br.readLine();

        // Validate and sanitize the input to prevent command injection
        if (!isValidCommand(command)) {
            System.out.println("Invalid command. Please try again.");
            return;
        }

        Process process = Runtime.getRuntime().exec(new String[]{"sh", "-c", "ping " + command});

        BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()));

        String line;
        while ((line = reader.readLine()) != null) {
            System.out.println(line);
        }
    }

    private static boolean isValidCommand(String command) {
        // Add validation logic here based on your requirements
        // For example, allow only specific commands or patterns
        return !command.contains(";") && !command.contains("|");
    }
}

